"use client";

import * as PopoverPrimitive from "@radix-ui/react-popover";
import { AnimatePresence, motion } from "motion/react";
import * as React from "react";

import { cn } from "@/lib/utils";

import { MotionConfig, useReducedMotion } from "motion/react";
import { createContext, useContext } from "react";

interface ReducedMotionProp {
  reducedMotion?: boolean;
}

const ReducedMotionOverrideContext = createContext(false);

function useResolvedReducedMotion(reducedMotion?: boolean) {
  const reducedMotionOverride = useContext(ReducedMotionOverrideContext);
  const prefersReducedMotion = useReducedMotion() ?? false;

  return Boolean(
    reducedMotion || reducedMotionOverride || prefersReducedMotion
  );
}

function ReducedMotionConfig({
  children,
  reducedMotion,
}: ReducedMotionProp & {
  children: import("react").ReactNode;
}) {
  const resolvedReducedMotion = useResolvedReducedMotion(reducedMotion);

  return (
    <MotionConfig reducedMotion={resolvedReducedMotion ? "always" : "user"}>
      {children}
    </MotionConfig>
  );
}

const lightTokens = [
  "[--background:#ffffff]",
  "[--foreground:#111111]",
  "[--primary:#111111]",
  "[--secondary:#646b75]",
  "[--surface-border:#e9edf2]",
  "[--border:#e3e7ec]",
  "[--card:#ffffff]",
  "[--card-foreground:#111111]",
  "[--muted:#f5f7fa]",
  "[--muted-foreground:#6d7480]",
  "[--accent:#f3f5f8]",
  "[--accent-foreground:#111111]",
  "[--input:#e3e7ec]",
  "[--ring:rgba(17,17,17,0.16)]",
  "[--destructive:#dc2626]",
  "[--paper:#fcfcfd]",
  "[--popover-foreground:#111111]",
  "[--brand:#0ea5e9]",
  "[--brand-soft:#bae6fd]",
  "[--shadow-soft:0_18px_38px_-24px_rgba(15,23,42,0.35)]",
];

const aliasTokens = [
  "[--color-background:var(--background)]",
  "[--color-foreground:var(--foreground)]",
  "[--color-primary:var(--primary)]",
  "[--color-secondary:var(--secondary)]",
  "[--color-border:var(--border)]",
  "[--color-card:var(--card)]",
  "[--color-card-foreground:var(--card-foreground)]",
  "[--color-muted:var(--muted)]",
  "[--color-muted-foreground:var(--muted-foreground)]",
  "[--color-accent:var(--accent)]",
  "[--color-accent-foreground:var(--accent-foreground)]",
  "[--color-input:var(--input)]",
  "[--color-ring:var(--ring)]",
  "[--color-destructive:var(--destructive)]",
  "[--color-paper:var(--paper)]",
  "[--color-popover-foreground:var(--popover-foreground)]",
  "[--color-brand:var(--brand)]",
  "[--color-brand-soft:var(--brand-soft)]",
];

const darkTokens = [
  "dark:[--background:#111111]",
  "dark:[--foreground:#f6f3ec]",
  "dark:[--primary:#f6f3ec]",
  "dark:[--secondary:#cbc6bb]",
  "dark:[--surface-border:#2a2a25]",
  "dark:[--border:#2b2a25]",
  "dark:[--card:#111111]",
  "dark:[--card-foreground:#f6f3ec]",
  "dark:[--muted:#171716]",
  "dark:[--muted-foreground:#9a958a]",
  "dark:[--accent:#1a1a18]",
  "dark:[--accent-foreground:#f6f3ec]",
  "dark:[--input:#2b2a25]",
  "dark:[--ring:rgba(246,243,236,0.18)]",
  "dark:[--destructive:#f87171]",
  "dark:[--paper:#171716]",
  "dark:[--popover-foreground:#f6f3ec]",
  "dark:[--brand:#38bdf8]",
  "dark:[--brand-soft:#0c4a6e]",
  "dark:[--shadow-soft:0_20px_44px_-28px_rgba(0,0,0,0.6)]",
];

const registryTheme = [
  ...lightTokens,
  ...aliasTokens,
  ...darkTokens,
].join(" ");

type Side = "top" | "right" | "bottom" | "left";

type PopoverContextValue = {
  open: boolean;
};

const PopoverContext = React.createContext<PopoverContextValue | null>(null);

const initialOffset: Record<Side, { x: number; y: number }> = {
  top: { x: 0, y: 10 },
  right: { x: -10, y: 0 },
  bottom: { x: 0, y: -10 },
  left: { x: 10, y: 0 },
};

const PANEL_SPRING = {
  type: "spring",
  stiffness: 240,
  damping: 22,
  mass: 0.78,
} as const;

const usePopover = () => {
  const context = React.useContext(PopoverContext);

  if (!context) {
    throw new Error("Popover components must be used inside Popover");
  }

  return context;
};

type PopoverProps = React.ComponentPropsWithoutRef<
  typeof PopoverPrimitive.Root
> &
  ReducedMotionProp;

const Popover = ({
  children,
  defaultOpen = false,
  onOpenChange,
  open: openProp,
  reducedMotion,
  ...props
}: PopoverProps) => {
  const isControlled = openProp !== undefined;
  const [uncontrolledOpen, setUncontrolledOpen] = React.useState(defaultOpen);
  const open = isControlled ? openProp : uncontrolledOpen;

  const handleOpenChange = React.useCallback(
    (nextOpen: boolean) => {
      if (!isControlled) {
        setUncontrolledOpen(nextOpen);
      }

      onOpenChange?.(nextOpen);
    },
    [isControlled, onOpenChange]
  );

  return (
    <ReducedMotionConfig reducedMotion={reducedMotion}>
      <PopoverContext.Provider value={{ open }}>
        <PopoverPrimitive.Root
          {...props}
          onOpenChange={handleOpenChange}
          open={open}
        >
          {children}
        </PopoverPrimitive.Root>
      </PopoverContext.Provider>
    </ReducedMotionConfig>
  );
};
Popover.displayName = "Popover";

type PopoverTriggerProps = React.ComponentPropsWithoutRef<
  typeof PopoverPrimitive.Trigger
>;

const PopoverTrigger = React.forwardRef<
  React.ElementRef<typeof PopoverPrimitive.Trigger>,
  PopoverTriggerProps
>(({ asChild, className, ...props }, ref) => {
  return (
    <PopoverPrimitive.Trigger
      asChild={asChild}
      className={cn(
        !asChild && registryTheme,
        !asChild &&
          "inline-flex min-h-11 min-w-11 touch-manipulation items-center justify-center rounded-md focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        className
      )}
      ref={ref}
      {...props}
    />
  );
});
PopoverTrigger.displayName = "PopoverTrigger";

const PopoverAnchor = PopoverPrimitive.Anchor;

type PopoverContentProps = React.ComponentPropsWithoutRef<
  typeof PopoverPrimitive.Content
> & {
  open?: boolean;
};

type PopoverContentPanelProps = React.ComponentPropsWithoutRef<
  typeof motion.div
> & {
  "data-side"?: Side;
};

const PopoverContentPanel = React.forwardRef<
  HTMLDivElement,
  PopoverContentPanelProps
>(({ children, className, style, "data-side": dataSide, ...props }, ref) => {
  const resolvedSide = dataSide ?? "bottom";

  return (
    <motion.div
      animate={{ opacity: 1, scale: 1, x: 0, y: 0, filter: "blur(0px)" }}
      className={cn(
        registryTheme,
        "z-50 w-72 transform-gpu rounded-lg border border-border bg-white p-4 text-foreground shadow-lg outline-none will-change-[transform,opacity,filter] dark:bg-black",
        className
      )}
      exit={{
        opacity: 0,
        scale: 0.985,
        filter: "blur(4px)",
        ...initialOffset[resolvedSide],
        transition: { duration: 0.2, ease: "easeIn" },
      }}
      initial={{
        opacity: 0,
        scale: 0.955,
        filter: "blur(8px)",
        ...initialOffset[resolvedSide],
      }}
      layout="size"
      ref={ref}
      style={{
        transformOrigin: "var(--radix-popover-content-transform-origin)",
        ...style,
      }}
      transition={PANEL_SPRING}
      {...props}
    >
      {children}
    </motion.div>
  );
});
PopoverContentPanel.displayName = "PopoverContentPanel";

/**
 * Internal content body — uses Radix's placement data for direction-aware
 * motion and lets Motion smoothly animate size changes while content updates.
 */
const PopoverContentBody = React.forwardRef<
  React.ElementRef<typeof PopoverPrimitive.Content>,
  PopoverContentProps
>(
  (
    {
      align = "center",
      avoidCollisions = true,
      children,
      className,
      collisionPadding = 12,
      side = "bottom",
      sideOffset = 8,
      ...props
    },
    ref
  ) => {
    return (
      <PopoverPrimitive.Content
        align={align}
        asChild
        avoidCollisions={avoidCollisions}
        collisionPadding={collisionPadding}
        ref={ref}
        side={side}
        sideOffset={sideOffset}
        {...props}
      >
        <PopoverContentPanel className={className}>
          {children}
        </PopoverContentPanel>
      </PopoverPrimitive.Content>
    );
  }
);
PopoverContentBody.displayName = "PopoverContentBody";

/**
 * Wrap PopoverContent with AnimatePresence so exit animations play.
 * Presence follows the nearest Popover root state.
 * `open` is accepted for backwards compatibility but is no longer required.
 */
const PopoverContent = React.forwardRef<
  React.ElementRef<typeof PopoverPrimitive.Content>,
  PopoverContentProps
>(({ open: _open, ...props }, ref) => {
  const { open: contextOpen } = usePopover();

  return (
    <AnimatePresence>
      {contextOpen ? (
        <PopoverPrimitive.Portal forceMount>
          <PopoverContentBody ref={ref} {...props} />
        </PopoverPrimitive.Portal>
      ) : null}
    </AnimatePresence>
  );
});
PopoverContent.displayName = "PopoverContent";

export { Popover, PopoverTrigger, PopoverContent, PopoverAnchor };
